import React, { useState, useEffect } from 'react';
import './App.css';
import { db, auth } from './firebase';
import { collection, addDoc, getDocs, doc, updateDoc } from 'firebase/firestore';
import { signInWithEmailAndPassword, signOut } from 'firebase/auth';

const COORD_MASC = '5551984572063';
const COORD_FEM = '5551984572064';

const getCoord = (modalidade) => {
  const fem = ['Quarteto Feminino', 'Dupla Feminina'];
  return fem.includes(modalidade) ? COORD_FEM : COORD_MASC;
};

const abrirWhatsApp = (numero, mensagem) => {
  const url = 'https://wa.me/' + numero + '?text=' + encodeURIComponent(mensagem);
  window.open(url, '_blank');
};

export default function App() {
  const [tela, setTela] = useState('home');
  const [usuario, setUsuario] = useState(null);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const jogoId = params.get('jogo');
    const jogador = params.get('jogador');
    if (jogoId && jogador) setTela('confirmar');
  }, []);

  return (
    <div className="app">
      {tela === 'home' && <Home setTela={setTela} />}
      {tela === 'login' && <Login setTela={setTela} setUsuario={setUsuario} />}
      {tela === 'desafio' && <Desafio setTela={setTela} />}
      {tela === 'painel' && <Painel setTela={setTela} usuario={usuario} setUsuario={setUsuario} />}
      {tela === 'confirmar' && <Confirmar />}
    </div>
  );
}

