function Login({ setTela, setUsuario }) {
  const [email, setEmail] = useState(localStorage.getItem('email_coord') || '');
  const [senha, setSenha] = useState('');
  const [erro, setErro] = useState('');
  const [load, setLoad] = useState(false);
  const [lembrar, setLembrar] = useState(!!localStorage.getItem('email_coord'));

  const entrar = async () => {
    setErro('');
    setLoad(true);
    try {
      const r = await signInWithEmailAndPassword(auth, email, senha);
      if (lembrar) localStorage.setItem('email_coord', email);
      else localStorage.removeItem('email_coord');
      setUsuario(r.user);
      setTela('painel');
    } catch(e) {
      setErro('Email ou senha incorretos.');
    }
    setLoad(false);
  };

  return (
    <div className="login">
      <button className="btn-back" onClick={() => setTela('home')}>Voltar</button>
      <img src={require('./logo-volei-tche.png')} alt="logo" className="logo-img" />
      <h2>Volei Tche</h2>
      <p className="sub">Area de gestao</p>
      {erro && <div className="erro-msg">{erro}</div>}
      <input type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} />
      <input type="password" placeholder="Senha" value={senha} onChange={e => setSenha(e.target.value)} />
      <div style={{display:'flex', alignItems:'center', gap:'8px', width:'100%'}}>
        <input type="checkbox" id="lembrar" checked={lembrar} onChange={e => setLembrar(e.target.checked)} />
        <label htmlFor="lembrar" style={{fontSize:'13px', color:'rgba(201,168,76,0.7)', cursor:'pointer'}}>Lembrar meu email</label>
      </div>
      <button className="btn-entrar" onClick={entrar} disabled={load}>
        {load ? 'Entrando...' : 'Entrar'}
      </button>
    </div>
  );
}

function Painel({ setTela, setUsuario }) {
  const [aba, setAba] = useState('jogos');
  const [desafios, setDesafios] = useState([]);
  const [jogos, setJogos] = useState([]);
  const [load, setLoad] = useState(true);
  const [form, setForm] = useState({ modalidade:'', data:'', hora:'', local:'', jogadores:'' });
  const mods = ['Quarteto Masculino','Quarteto Feminino','Quarteto Misto','Dupla Masculina','Dupla Feminina'];

  useEffect(() => { buscar(); }, []);

  const buscar = async () => {
    setLoad(true);
    const sd = await getDocs(collection(db, 'desafios'));
    setDesafios(sd.docs.map(d => ({id:d.id,...d.data()})));
    const sj = await getDocs(collection(db, 'jogos'));
    setJogos(sj.docs.map(d => ({id:d.id,...d.data()})).sort((a,b) => new Date(a.data) - new Date(b.data)));
    setLoad(false);
  };

  const criarJogo = async () => {
    if (!form.modalidade || !form.data || !form.hora) return alert('Preencha modalidade, data e horario.');
    const lista = form.jogadores.split(',').map(j => j.trim()).filter(j => j);
    await addDoc(collection(db, 'jogos'), {
      ...form, jogadores: lista, confirmacoes: {}, criadoEm: new Date().toISOString()
    });
    setForm({ modalidade:'', data:'', hora:'', local:'', jogadores:'' });
    buscar();
    setAba('jogos');
  };

  const aceitarDesafio = async (d) => {
    await updateDoc(doc(db, 'desafios', d.id), {status:'aceito'});
    const contato = d.contato.replace(/\D/g,'');
    if (contato.length >= 10) {
      const msg = 'Ola ' + d.time + '! O Volei Tche aceitou o desafio!\n\nModalidade: ' + d.modalidade + '\nData: ' + d.data + '\n\nAguardamos voces na quadra!';
      abrirWhatsApp(contato.length === 11 ? '55' + contato : contato, msg);
    }
    buscar();
  };

  const recusarDesafio = async (id) => {
    await updateDoc(doc(db, 'desafios', id), {status:'recusado'});
    buscar();
  };

  const copiarLink = (jogoId, jog) => {
    const base = window.location.href.split('?')[0];
    const link = base + '?jogo=' + jogoId + '&jogador=' + encodeURIComponent(jog);
    navigator.clipboard.writeText(link);
    alert('Link copiado!');
  };

  const convocarTodos = (j) => {
    const base = window.location.href.split('?')[0];
    let msg = 'Volei Tche - Convocacao!\n';
    msg += 'Modalidade: ' + j.modalidade + '\n';
    msg += 'Data: ' + j.data + ' as ' + j.hora + '\n';
    msg += 'Local: ' + (j.local || 'A confirmar') + '\n\n';
    msg += 'Confirme sua presenca clicando no seu link:\n\n';
    (j.jogadores || []).forEach(jog => {
      const link = base + '?jogo=' + j.id + '&jogador=' + encodeURIComponent(jog);
      msg += jog + ':\n' + link + '\n\n';
    });
    navigator.clipboard.writeText(msg);
    alert('Mensagem com todos os links copiada! Cole no grupo do WhatsApp.');
  };

  const sair = async () => {
    await signOut(auth);
    setUsuario(null);
    setTela('home');
  };

  const bgS = s => s==='aceito' ? '#EAF3DE' : s==='recusado' ? '#FCEBEB' : '#FAEEDA';
  const corS = s => s==='aceito' ? '#27500A' : s==='recusado' ? '#791F1F' : '#633806';
  const txtS = s => s==='aceito' ? 'Aceito' : s==='recusado' ? 'Recusado' : 'Pendente';
  const bgC = s => s==='sim' ? '#EAF3DE' : s==='nao' ? '#FCEBEB' : '#FAEEDA';
  const corC = s => s==='sim' ? '#27500A' : s==='nao' ? '#791F1F' : '#633806';
  const txtC = s => s==='sim' ? 'Confirmado' : s==='nao' ? 'Nao vai' : 'Pendente';

  const hoje = new Date();
  const diasNoMes = new Date(hoje.getFullYear(), hoje.getMonth()+1, 0).getDate();
  const primeiroDia = new Date(hoje.getFullYear(), hoje.getMonth(), 1).getDay();
  const nomeMes = hoje.toLocaleString('pt-BR', {month:'long', year:'numeric'});
  const mesAtual = hoje.getFullYear() + '-' + String(hoje.getMonth()+1).padStart(2,'0');

  const jogosNoDia = (dia) => {
    const dataStr = hoje.getFullYear() + '-' + String(hoje.getMonth()+1).padStart(2,'0') + '-' + String(dia).padStart(2,'0');
    return jogos.filter(j => j.data === dataStr);
  };

  return (
    <div className="painel">
      <div className="painel-header">
        <div><h2>Painel do Coordenador</h2><p className="sub">Volei Tche</p></div>
        <button className="btn-sair" onClick={sair}>Sair</button>
      </div>
      <div className="painel-abas">
        {['jogos','calendario','novo','desafios'].map(a => (
          <div key={a} className={'painel-aba' + (aba===a ? ' ativa' : '')} onClick={() => setAba(a)}>
            {a==='novo' ? '+ Novo' : a==='jogos' ? 'Jogos' : a==='calendario' ? 'Agenda' : 'Desafios'}
          </div>
        ))}
      </div>
      {load ? <div className="carregando">Carregando...</div> : (
        <div className="painel-body">

          {aba==='calendario' && (
            <div style={{padding:'16px'}}>
              <div className="cal-titulo">{nomeMes.charAt(0).toUpperCase() + nomeMes.slice(1)}</div>
              <div className="cal-grid">
                {['D','S','T','Q','Q','S','S'].map((d,i) => (
                  <div key={i} className="cal-header-dia">{d}</div>
                ))}
                {Array.from({length: primeiroDia}).map((_,i) => <div key={'e'+i} />)}
                {Array.from({length: diasNoMes}).map((_,i) => {
                  const dia = i+1;
                  const temJogo = jogosNoDia(dia).length > 0;
                  const ehHoje = dia === hoje.getDate();
                  return (
                    <div key={dia} className={'cal-dia' + (ehHoje ? ' cal-hoje' : '') + (temJogo ? ' cal-tem-jogo' : '')}>
                      {dia}
                      {temJogo && <div className="cal-ponto"></div>}
                    </div>
                  );
                })}
              </div>
              <div style={{marginTop:'16px'}}>
                <div style={{fontSize:'13px', fontWeight:'500', color:'#333', marginBottom:'10px'}}>Jogos do mes:</div>
                {jogos.filter(j => j.data && j.data.startsWith(mesAtual)).length === 0 ? (
                  <div className="vazio"><p>Nenhum jogo este mes.</p></div>
                ) : jogos.filter(j => j.data && j.data.startsWith(mesAtual)).map(j => (
                  <div key={j.id} className="desafio-card" style={{marginBottom:'8px'}}>
                    <div className="desafio-card-header">
                      <strong>{j.modalidade}</strong>
                      <span style={{fontSize:'12px', color:'#666'}}>{j.data} {j.hora}</span>
                    </div>
                    <p style={{fontSize:'12px', color:'#666'}}>{j.local}</p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {aba==='novo' && (
            <div className="novo-jogo-form">
              <h3>Novo Jogo</h3>
              <label>Modalidade</label>
              <select value={form.modalidade} onChange={e => setForm({...form, modalidade:e.target.value})}>
                <option value="">Selecione...</option>
                {mods.map(m => <option key={m}>{m}</option>)}
              </select>
              <label>Data</label>
              <input type="date" value={form.data} onChange={e => setForm({...form, data:e.target.value})} />
              <label>Horario</label>
              <input type="time" value={form.hora} onChange={e => setForm({...form, hora:e.target.value})} />
              <label>Local</label>
              <input placeholder="Ex: Quadra A" value={form.local} onChange={e => setForm({...form, local:e.target.value})} />
              <label>Jogadores (separados por virgula)</label>
              <input placeholder="Ex: Gabriel, Rafael, Joao" value={form.jogadores} onChange={e => setForm({...form, jogadores:e.target.value})} />
              <button className="btn-entrar" onClick={criarJogo}>Criar Jogo</button>
            </div>
          )}

          {aba==='jogos' && (
            <div className="desafios-lista">
              {jogos.length===0 ? (
                <div className="vazio">
                  <p>Nenhum jogo criado.</p>
                  <button className="btn-next" onClick={() => setAba('novo')}>Criar jogo</button>
                </div>
              ) : jogos.map(j => (
                <div key={j.id} className="desafio-card">
                  <div className="desafio-card-header">
                    <strong>{j.modalidade}</strong>
                    <span style={{fontSize:'12px', color:'#666'}}>{j.data} {j.hora}</span>
                  </div>
                  <p style={{fontSize:'12px', color:'#666', marginBottom:'8px'}}>{j.local}</p>
                  <button className="btn-convocar-todos" onClick={() => convocarTodos(j)}>
                    Convocar todos pelo WhatsApp
                  </button>
                  {(j.jogadores||[]).map((jog,i) => (
                    <div key={i} className="jogador-row">
                      <div className="jogador-info">
                        <div className="jogador-av">{jog.charAt(0)}</div>
                        <span>{jog}</span>
                      </div>
                      <div style={{display:'flex', alignItems:'center', gap:'6px'}}>
                        <span style={{
                          fontSize:'11px', padding:'2px 8px', borderRadius:'99px',
                          background: bgC(j.confirmacoes && j.confirmacoes[jog]),
                          color: corC(j.confirmacoes && j.confirmacoes[jog])
                        }}>
                          {txtC(j.confirmacoes && j.confirmacoes[jog])}
                        </span>
                        <button className="btn-wa" onClick={() => copiarLink(j.id, jog)}>Copiar</button>
                      </div>
                    </div>
                  ))}
                </div>
              ))}
            </div>
          )}

          {aba==='desafios' && (
            <div className="desafios-lista">
              {desafios.length===0 ? (
                <div className="vazio"><p>Nenhum desafio.</p></div>
              ) : desafios.map(d => (
                <div key={d.id} className="desafio-card">
                  <div className="desafio-card-header">
                    <strong>{d.time}</strong>
                    <span style={{background:bgS(d.status), color:corS(d.status), fontSize:'11px', padding:'3px 10px', borderRadius:'99px'}}>
                      {txtS(d.status)}
                    </span>
                  </div>
                  <div className="desafio-card-info">
                    <p>{d.modalidade}</p><p>{d.data}</p><p>{d.contato}</p>
                  </div>
                  {d.status==='pendente' && (
                    <div className="desafio-card-acoes">
                      <button className="btn-aceitar" onClick={() => aceitarDesafio(d)}>Aceitar</button>
                      <button className="btn-recusar" onClick={() => recusarDesafio(d.id)}>Recusar</button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function Confirmar() {
  const [jogador, setJogador] = useState('');
  const [jogo, setJogo] = useState(null);
  const [load, setLoad] = useState(true);
  const [respondido, setRespondido] = useState(false);
  const [resposta, setResposta] = useState('');

  useEffect(() => {
    const p = new URLSearchParams(window.location.search);
    const jogoId = p.get('jogo');
    const jog = decodeURIComponent(p.get('jogador') || '');
    setJogador(jog);
    getDocs(collection(db, 'jogos')).then(snap => {
      const found = snap.docs.find(d => d.id===jogoId);
      if (found) {
        const data = {id:found.id, ...found.data()};
        setJogo(data);
        if (data.confirmacoes && data.confirmacoes[jog]) {
          setRespondido(true);
          setResposta(data.confirmacoes[jog]);
        }
      }
      setLoad(false);
    });
  }, []);

  const confirmar = async (r) => {
    const p = new URLSearchParams(window.location.search);
    const jogoId = p.get('jogo');
    await updateDoc(doc(db, 'jogos', jogoId), {['confirmacoes.' + jogador]: r});
    setResposta(r);
    setRespondido(true);
  };

  if (load) return <div className="carregando">Carregando...</div>;

  return (
    <div className="confirmar">
      <div className="confirmar-header">
        <img src={require('./logo-volei-tche.png')} alt="logo" className="logo-img-mini" />
        <div><h2>Volei Tche</h2><p className="sub">Confirme sua presenca</p></div>
      </div>
      {jogo && (
        <div className="confirmar-body">
          <div className="info-card">
            <div className="info-row">{jogo.modalidade}</div>
            <div className="info-row">Data: {jogo.data}</div>
            <div className="info-row">Hora: {jogo.hora}</div>
            <div className="info-row">Local: {jogo.local || 'A confirmar'}</div>
          </div>
          {!respondido ? (
            <div>
              <div className="confirmar-pergunta">{jogador}, vai jogar?</div>
              <button className="btn-sim" onClick={() => confirmar('sim')}>Sim, vou jogar!</button>
              <button className="btn-nao" onClick={() => confirmar('nao')}>Nao consigo ir</button>
            </div>
          ) : (
            <div className="respondido" style={{textAlign:'center'}}>
              {resposta==='sim'
                ? <div><h3 style={{color:'#27500A'}}>Presenca confirmada!</h3><p style={{color:'#666', marginTop:'8px'}}>Ate o jogo, {jogador}!</p></div>
                : <div><h3 style={{color:'#791F1F'}}>Presenca recusada</h3><p style={{color:'#666', marginTop:'8px'}}>Da proxima, {jogador}!</p></div>
              }
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function Desafio({ setTela }) {
  const [passo, setPasso] = useState(1);
  const [dados, setDados] = useState({time:'', contato:'', modalidade:'', data:''});
  const mods = ['Quarteto Masculino','Quarteto Feminino','Quarteto Misto','Dupla Masculina','Dupla Feminina'];
  const datas = [
    {dia:'Sab 24/05', hora:'19h00', livre:true},
    {dia:'Dom 25/05', hora:'10h00', livre:true},
    {dia:'Sab 31/05', hora:'19h00', livre:false},
    {dia:'Dom 01/06', hora:'10h00', livre:true},
    {dia:'Sab 07/06', hora:'19h00', livre:true},
    {dia:'Dom 08/06', hora:'10h00', livre:false},
  ];

  const enviar = async () => {
    try {
      await addDoc(collection(db, 'desafios'), {
        ...dados, status: 'pendente', criadoEm: new Date().toISOString()
      });
      const coord = getCoord(dados.modalidade);
      const msg = 'Novo desafio recebido!\n\nTime: ' + dados.time + '\nModalidade: ' + dados.modalidade + '\nData: ' + dados.data + '\nContato: ' + dados.contato + '\n\nAcesse o app para aceitar ou recusar.';
      abrirWhatsApp(coord, msg);
      setPasso(4);
    } catch(e) {
      alert('Erro ao enviar.');
    }
  };

  return (
    <div className="desafio">
      <div className="desafio-header">
        <button className="btn-back" onClick={() => passo===1 ? setTela('home') : setPasso(passo-1)}>Voltar</button>
        <div><h2>Desafiar o Volei Tche</h2><p className="sub">Passo {passo} de 3</p></div>
        <div className="progress"><div className="progress-fill" style={{width:((passo/3)*100)+'%'}}></div></div>
      </div>
      <div className="desafio-body">
        {passo===1 && (
          <div>
            <h3>Seus dados</h3>
            <input placeholder="Nome do seu time" value={dados.time} onChange={e => setDados({...dados, time:e.target.value})} />
            <input placeholder="Seu nome" />
            <input placeholder="WhatsApp com DDD Ex: 51999990001" value={dados.contato} onChange={e => setDados({...dados, contato:e.target.value})} />
            <button className="btn-next" onClick={() => setPasso(2)}>Proximo</button>
          </div>
        )}
        {passo===2 && (
          <div>
            <h3>Modalidade</h3>
            {mods.map(m => (
              <div key={m} className={'mod-item' + (dados.modalidade===m ? ' selecionado' : '')} onClick={() => setDados({...dados, modalidade:m})}>
                <span>{m}</span>{dados.modalidade===m && <span>ok</span>}
              </div>
            ))}
            <button className="btn-next" onClick={() => setPasso(3)} disabled={!dados.modalidade}>Proximo</button>
          </div>
        )}
        {passo===3 && (
          <div>
            <h3>Escolha uma data</h3>
            <div className="datas-grid">
              {datas.map((d,i) => (
                <div key={i} className={'data-cell' + (!d.livre ? ' ocupado' : '') + (dados.data===d.dia ? ' picked' : '')} onClick={() => d.livre && setDados({...dados, data:d.dia})}>
                  <strong>{d.dia}</strong><span>{d.hora}</span>
                  <small>{d.livre ? (dados.data===d.dia ? 'Selecionado' : 'Disponivel') : 'Ocupado'}</small>
                </div>
              ))}
            </div>
            <button className="btn-next" onClick={enviar} disabled={!dados.data}>Enviar desafio!</button>
          </div>
        )}
        {passo===4 && (
          <div style={{textAlign:'center', padding:'20px'}}>
            <h3 style={{color:'#0e1e12', marginBottom:'8px'}}>Desafio enviado!</h3>
            <p style={{color:'#666', marginBottom:'20px'}}>O coordenador foi notificado pelo WhatsApp!</p>
            <div style={{background:'#f5f5f5', borderRadius:'10px', padding:'14px', textAlign:'left'}}>
              <p><strong>Time:</strong> {dados.time}</p>
              <p><strong>Modalidade:</strong> {dados.modalidade}</p>
              <p><strong>Data:</strong> {dados.data}</p>
              <p><strong>Contato:</strong> {dados.contato}</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
